import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

// [id, elementDescription, whereFound, usedFor, funFact]
type Row = [number, string, string, string, string]

const facts: Row[] = [
  [1, 'The lightest and most abundant element in the universe, making up about 75% of all normal matter by mass.', 'Found in water, organic compounds, and most living things. The primary component of stars including the Sun.', 'Rocket fuel, petroleum refining, and producing ammonia for fertilizers. Emerging as a clean energy carrier in fuel cells.', 'A single hydrogen atom consists of just one proton and one electron — the simplest atom possible.'],
  [2, 'The second most abundant element in the universe and the lightest noble gas. Colorless, odorless, and completely non-reactive.', 'Formed by radioactive decay deep in the Earth, then trapped in natural gas deposits. Helium slowly escapes into space over time.', 'Fills balloons and blimps, cools MRI magnets and particle accelerators, and is used in deep-sea diving gas mixtures.', 'Helium was discovered on the Sun before it was found on Earth — astronomers spotted its spectral signature in 1868, 27 years before it was isolated here.'],
  [3, 'The lightest metal and the least dense solid element, soft enough to cut with a knife.', 'Found in mineral springs, seawater, and hard rock minerals like spodumene. The largest deposits are in salt flats in Chile, Argentina, and Bolivia.', 'The dominant material in rechargeable batteries — every smartphone, laptop, and electric vehicle depends on lithium. Also used to treat bipolar disorder.', "Lithium catches fire when it touches water, yet it's safe enough to be prescribed as a mood stabilizer."],
  [4, 'A rare, hard, silvery-white metal that is exceptionally lightweight yet very stiff — stiffer than steel at a fraction of the weight.', 'Found in minerals like beryl (the same mineral that gives us emeralds and aquamarines).', 'Space telescope mirrors, X-ray windows (nearly transparent to X-rays), and high-performance aerospace components.', 'Beryllium dust is one of the most toxic substances known — inhaling it can cause a permanent, incurable lung disease called berylliosis.'],
  [5, 'A metalloid with unusual properties — it can be as hard as diamond in its crystal form, yet soft and powdery in its amorphous form.', "Concentrated in arid regions through evaporation of ancient lake beds. Death Valley in California was a major historical source — it's in Borax soap's name..", 'Borosilicate glass (Pyrex), detergents (borax), and as a neutron absorber in nuclear reactor control rods.', "Boron is essential for plant cell wall structure — without it, plants can't grow. Yet it's toxic to insects, making it a natural pesticide."],
  [6, 'The basis of all known life — every living thing is built around carbon chains. The fourth most abundant element in the universe by mass.', 'In all living things, in the atmosphere as CO₂, in the ground as coal, oil, and natural gas, and in rocks as limestone.', 'Steel (as an alloy with iron), pencils (graphite), diamonds, and the backbone of every plastic, drug, and fuel ever made.', 'Carbon can exist as the hardest natural substance (diamond) or one of the softest (graphite) — both are pure carbon, just arranged differently.'],
  [7, 'A colorless, odorless gas that makes up 78% of Earth\'s atmosphere. Essential to all life as a component of proteins and DNA.', 'Almost entirely in the atmosphere. Fixed from the air into soil by specialized bacteria and lightning.', 'Fertilizers (via the Haber process), liquid nitrogen for freezing and cooling, and as an inert atmosphere for sensitive manufacturing.', 'The Haber process for making nitrogen fertilizer feeds roughly half the world\'s population. Without it, we couldn\'t grow enough food for 8 billion people.'],
  [8, 'The most abundant element in Earth\'s crust and the third most abundant in the universe. Essential to almost all life for respiration.', "Makes up 21% of Earth's atmosphere, 89% of water by mass, and nearly half of all crustal rock.", 'Breathing (medical oxygen), steel production, rocket propellant, and water treatment.', "Earth's oxygen-rich atmosphere is almost entirely biological in origin — before life existed, there was essentially no free oxygen here."],
  [9, 'The most reactive and electronegative element on the periodic table — it attacks almost every substance including glass, concrete, and even some noble gases.', 'Found in minerals like fluorite and fluorapatite (the mineral in tooth enamel). Never found as free gas in nature.', "Toothpaste (fluoride strengthens enamel), non-stick cookware (Teflon), and refrigerants.", 'Fluorine is so reactive that it took 74 years of attempts to isolate it — several chemists died or were permanently injured trying.'],
  [10, 'A noble gas that glows brilliant orange-red when electricity passes through it. The fifth most abundant element in the universe.', "Present in tiny amounts in Earth's atmosphere (about 1 part in 65,000). Produced commercially by distilling liquid air.", 'Neon signs (classic orange-red glow), lasers, and as a cryogenic refrigerant.', "Despite its name being on every sign, most colored signs use other gases — only the orange-red color is actual neon. Blue is mercury, green is often argon with mercury."],
  [11, 'A soft, silvery metal so reactive it must be stored in oil to prevent it from reacting with air moisture. Essential to nerve function in all animals.', 'Never found as pure metal in nature. Abundant as sodium chloride (table salt) in oceans and salt deposits worldwide.', 'Table salt (NaCl), soap manufacturing, streetlights (sodium vapor lamps give that yellow glow), and as a coolant in some nuclear reactors.', 'Throwing sodium into water produces hydrogen gas that ignites from the reaction heat — the bigger the piece, the more violent the explosion.'],
  [12, 'A lightweight, silvery-white metal that burns with a brilliant white flame. The central atom in chlorophyll, the molecule that makes photosynthesis possible.', "Eighth most abundant element in Earth's crust. Found in seawater, dolomite rock, and magnesite minerals.", 'Lightweight alloys for aircraft and cars, fireworks and flares (the bright white sparkle), and nutritional supplements.', 'Magnesium fires cannot be put out with water — water actually makes them burn more intensely by releasing hydrogen gas.'],
  [13, 'The most abundant metal in Earth\'s crust, lightweight, corrosion-resistant, and infinitely recyclable. Despite its abundance, it was once more valuable than gold.', "Third most abundant element in Earth's crust, primarily in the mineral bauxite.", 'Aircraft, cars, beverage cans, foil, construction materials, and virtually every industry on Earth.', "The Washington Monument's apex is capped with aluminum — placed in 1884 when aluminum was a precious metal, more expensive than silver."],
  [14, "A metalloid that forms the backbone of modern computing. The second most abundant element in Earth's crust after oxygen.", "Nearly everywhere in Earth's crust as silicon dioxide (quartz, sand) and silicate minerals.", 'Semiconductors, solar cells, glass, ceramics, and computer chips. Nearly all modern electronics depend on silicon.', '"Silicon Valley" produces nothing with silicon per se — the name comes from the era when computer chips were cut from pure silicon derived from sand.'],
  [15, 'A highly reactive nonmetal that exists in several forms. White phosphorus glows in the dark and ignites spontaneously in air.', 'Never found as a free element. Found in phosphate rocks and in all living organisms (in DNA and ATP, the energy molecule of life).', 'Fertilizers (the most critical agricultural use), matches, and detergents.', "Phosphorus is the only element named for a property it doesn't have in its stable form — 'phosphorus' means 'light bearer,' but the safe red form doesn't glow at all."],
  [16, 'A bright yellow solid found near volcanoes and hot springs. One of the oldest elements known — mentioned in the Bible as "brimstone."', 'Found in pure form near volcanoes, in mineral deposits, and dissolved in hot springs. Also produced when oil and gas are refined.', 'Sulfuric acid (the most produced industrial chemical in the world), fertilizers, rubber vulcanization, and gunpowder.', 'The smell of rotten eggs is hydrogen sulfide — sulfur itself is almost odorless. Many sulfur compounds have extremely powerful smells at incredibly low concentrations.'],
  [17, 'A yellow-green toxic gas used as a chemical weapon in World War I. Yet in small amounts it\'s essential to life and keeps our drinking water safe.', 'Found in salt deposits and dissolved in seawater as chloride ions. Never found as free gas in nature.', 'Water purification, bleach, PVC plastic, and pharmaceuticals (many drugs contain chlorine atoms).', "The distinctive smell of a swimming pool isn't chlorine itself — it's chloramines, formed when chlorine reacts with nitrogen compounds in urine and sweat."],
  [18, "The most abundant noble gas in Earth's atmosphere, making up about 1% of the air. Completely inert — it doesn't react with anything under normal conditions.", 'Produced continuously in Earth\'s crust by radioactive decay of potassium-40, then seeps into the atmosphere over geological time.', 'Filling incandescent and fluorescent light bulbs (prevents the filament from burning), welding shield gas, and preserving historical documents in airtight cases.', 'Geologists use argon to date ancient rocks — because potassium-40 decays to argon-40 at a known rate, measuring the ratio tells you how old the rock is.'],
  [19, "A soft, silvery alkali metal essential to every living cell for regulating fluid balance and nerve signals. Its symbol K comes from the Latin 'kalium.'", "Never found as pure metal in nature. Found in potash minerals and dissolved in seawater.", 'Fertilizers (the K in NPK plant food), gunpowder, and as a salt substitute for people with high blood pressure.', 'A tiny fraction of all potassium (0.012%) is radioactive potassium-40. The potassium in your body makes you measurably radioactive — a banana has enough to set off sensitive radiation detectors.'],
  [20, "The fifth most abundant element in Earth's crust and the most abundant metal in the human body.", "Widespread as limestone, chalk, marble, and gypsum. Also dissolved in hard water.", 'Construction (concrete, cement, plaster), steel production, and as a nutritional supplement for bones and teeth.', 'Calcium is so reactive as a pure metal that it reacts with both air and water — yet we consume it safely because it is never free in the body, always bonded in compounds.'],
  [21, 'A rare, silvery-white metal with unusually low density for a transition metal. Largely unknown to the public despite being more common than lead.', 'Scattered in trace amounts across many minerals but rarely concentrated enough to mine economically — making it expensive despite its abundance.', 'High-performance aluminum alloys for baseball bats, bicycle frames, and aircraft parts (a small amount dramatically strengthens aluminum).', 'Scandium was predicted by Mendeleev in 1871 as "eka-boron" before it was discovered in 1879 — one of his greatest predictions about missing elements.'],
  [22, 'A strong, lightweight, and extraordinarily corrosion-resistant metal. As strong as steel but 45% lighter.', "The ninth most abundant element in Earth's crust, found in minerals like ilmenite and rutile.", 'Aerospace (jet engines, spacecraft), medical implants (hips, dental implants), and high-end sports equipment.', 'Titanium is completely biocompatible — human bone actually grows onto titanium implants, integrating them permanently into the body.'],
  [23, 'A hard, silvery-gray transition metal with exceptional strength and the ability to form many colorful compounds.', 'Found in about 65 minerals worldwide, and in small amounts in crude oil — refinery residues are a major source.', 'Steel alloys (a tiny amount makes steel much stronger), and vanadium redox batteries for large-scale energy storage.', 'Vanadium compounds are found in the blood of sea cucumbers — they use it to bind oxygen, similar to how iron works in human hemoglobin.'],
  [24, 'A hard, lustrous, highly corrosion-resistant metal. The element responsible for the brilliant red of rubies and the green of emeralds.', 'Found primarily as chromite ore. South Africa and Kazakhstan hold the world\'s largest deposits.', 'Chrome plating, stainless steel (chromium is what makes steel "stainless"), and leather tanning.', 'Chromium in trace amounts is an essential human nutrient that helps insulin function, but hexavalent chromium is a potent carcinogen — infamous from the Erin Brockovich case.'],
  [25, 'A hard, brittle, gray-white transition metal essential to steel production and to all known life.', "Fourth most common transition metal in Earth's crust. Found in pyrolusite ore and in mysterious potato-sized nodules on the ocean floor.", "Steel production (nearly all steel contains manganese), dry-cell batteries, and as a pigment (cave paintings from 30,000 years ago used manganese dioxide).", "The ocean floor is covered in manganese nodules that form spontaneously over millions of years and contain commercially interesting quantities of cobalt, nickel, and copper."],
  [26, "The most common element on Earth by mass (most of the core is iron), and the backbone of human civilization for 3,000 years.", "Abundant in Earth's core and crust. Found as iron oxide ores (hematite, magnetite) on every continent.", 'Steel (iron + carbon), construction, machinery, vehicles, and as an essential component of hemoglobin in blood.', 'Iron is the final element formed in a star\'s life cycle — when a star begins fusing iron, it starts to collapse, leading to a supernova. All iron on Earth came from ancient dead stars.'],
  [27, 'A hard, lustrous, silvery-blue magnetic metal. The source of the brilliant blue used in ancient glass and ceramics for thousands of years.', 'Found in cobaltite and smaltite ores. The Democratic Republic of Congo holds over 60% of the world\'s cobalt reserves.', 'Lithium-ion battery cathodes (essential for EVs and electronics), superalloys for jet engines, and blue pigments in paint and glass.', 'Cobalt-60, a radioactive isotope, is used in cancer radiation therapy and sterilizing medical equipment — it\'s one of the most widely used radioactive isotopes in medicine.'],
  [28, 'A hard, silvery-white, lustrous magnetic metal with high corrosion resistance. One of the most widely used industrial metals.', "Found in pentlandite and niccolite ores. Large deposits in Russia, Canada, and Australia.", 'Stainless steel, rechargeable batteries (nickel-metal hydride), coins, and electroplating.', "The Earth's core contains a large amount of nickel, and many meteorites are made of iron-nickel alloy — nickel content is one way geologists identify meteorites."],
  [29, 'A soft, reddish-gold metal and one of the first metals used by humans, over 10,000 years ago. The best natural conductor of electricity.', 'Found as native copper (pure metal in rock), and in ores like chalcopyrite. Chile is the world\'s largest producer.', 'Electrical wiring (the backbone of all electrical infrastructure), plumbing, roofing, and coins.', 'Copper is naturally antimicrobial — bacteria, viruses, and fungi die on copper surfaces within hours. Hospitals are returning to copper door handles for infection control.'],
  [30, 'A bluish-white metal that corrodes very slowly and is essential to human biology — involved in over 300 enzyme reactions in the body.', 'Found in sphalerite ore. China, Australia, and Peru are the largest producers.', 'Galvanizing steel (zinc coating prevents rust), brass alloys, sunscreen, and dietary supplements.', "The first practical battery (Volta's pile, 1800) was made from zinc and copper discs — zinc's role in electrochemistry literally launched the electrical age."],
  [31, 'A soft, silvery metal with a melting point just above room temperature (29.8°C / 85.6°F) — it melts in your hand on a warm day.', 'No significant gallium ore deposits exist — it\'s extracted as a byproduct of processing bauxite for aluminum.', 'LEDs and solar cells (gallium arsenide), semiconductors, and in some thermometers as a non-toxic mercury substitute.', 'Gallium dissolves aluminum metal — a small gallium blob placed on an aluminum surface slowly "eats" through it over hours, turning solid metal into powder.'],
  [32, 'A lustrous, grayish-white metalloid that behaves as a semiconductor. One of the elements predicted by Mendeleev before its discovery.', 'Dispersed in trace amounts in zinc ores, coal, and some other minerals. No major concentrated deposits.', 'Fiber optic cables (germanium dioxide improves light transmission), infrared optics (cameras that see in the dark), and the world\'s first transistors.', 'The world\'s first working transistor (1947, Bell Labs) used germanium. Silicon later took over, but germanium is making a comeback in advanced chips.'],
  [33, 'A gray metalloid infamous as a poison but also essential to some semiconductors. Odorless and tasteless in its common form.', 'Found in arsenic sulfide minerals and as a byproduct of copper and gold smelting. Naturally contaminates groundwater in parts of Bangladesh, India, and the American West.', 'Wood preservatives, semiconductors (gallium arsenide), and historically in pesticides, pigments, and — notoriously — as a poison.', "Napoleon Bonaparte likely died of arsenic poisoning — analysis of his hair shows extremely high arsenic levels, possibly from green wallpaper dye in his damp room releasing arsenic gas."],
  [34, 'A nonmetal with photoconductive properties — it conducts electricity much better in light than in the dark — and an essential trace nutrient for humans.', 'A byproduct of copper refining. Found in soils unevenly distributed around the world; some regions have toxic levels, others have deficient levels.', "Photocopiers and laser printers (selenium drums), glass manufacturing (to decolorize glass), and nutritional supplements.", 'Selenium is the element with the narrowest margin between essential and toxic — the difference between a healthy dietary dose and a dangerous dose is surprisingly small.'],
  [35, 'One of only two elements that are liquid at room temperature (mercury is the other). A reddish-brown liquid with a pungent, choking smell.', "Found in seawater and underground brine deposits. Israel's Dead Sea is the most famous source.", "Flame retardants in electronics and furniture, water purification for hot tubs, and historically as a sedative drug.", "The Phoenicians' famous purple dye ('Tyrian purple') came from a bromine compound secreted by sea snails. It took 12,000 snails to make 1.4 grams of dye, making purple the color of royalty."],
  [36, 'A colorless, odorless noble gas that glows bright white-green in electrical discharge tubes. Its name comes from the Greek for "hidden."', "Present in tiny amounts in Earth's atmosphere (1 part per million). Produced commercially by distilling liquid air.", 'High-performance camera flashes, energy-efficient windows (krypton-filled double-pane windows insulate better than air), and lighting.', 'The international standard meter was once defined as 1,650,763.73 wavelengths of a specific spectral line of krypton-86. This was replaced in 1983 by a definition based on the speed of light.'],
  [37, 'A soft, silvery-white alkali metal so reactive it ignites spontaneously in air and explodes on contact with water.', 'Dispersed in trace amounts in many minerals, lepidolite mica being the most common source. Never found in concentrated deposits.', 'Atomic clocks (rubidium atomic clocks are the most common type used in GPS satellites), research, and specialty glass.', 'Rubidium was the first element discovered using a spectroscope — in 1861, Robert Bunsen spotted its unique red spectral lines in mineral water samples.'],
  [38, 'A soft, silvery-white alkaline earth metal that burns bright crimson red — the source of red fireworks and emergency flares.', 'Found in minerals celestite and strontianite. Named after Strontian, a village in Scotland where it was first discovered.', 'Red fireworks and signal flares, and formerly in CRT television screens. Strontium-90 (radioactive isotope) is studied in nuclear fallout research.', "Strontium-90, a radioactive isotope from nuclear fallout, is dangerous because the body mistakes it for calcium and incorporates it directly into bones and teeth."],
  [39, 'A silvery-white rare earth metal that is surprisingly common in Earth\'s crust but rarely heard of outside materials science.', "Dispersed in rare earth ore deposits. Moon rocks brought back by Apollo missions were unexpectedly rich in yttrium.", 'LED and phosphor lighting (the red phosphor in LED TVs is yttrium), superconductors, and cancer treatment via radioactive yttrium-90.', 'Four elements (yttrium, ytterbium, erbium, terbium) are all named after Ytterby, a single small village in Sweden where a peculiar mineral was found in 1787.'],
  [40, 'A strong, lustrous, grayish-white metal with exceptional corrosion resistance and near-total transparency to neutrons.', "Found in zircon mineral, one of the oldest minerals on Earth. Zircon crystals in Western Australia are over 4.4 billion years old — older than most rocks.", 'Nuclear reactor fuel rod cladding (it does not absorb neutrons), cubic zirconia gemstones (zirconium oxide), and industrial ceramics.', 'Zircon crystals are the oldest known material on Earth — older than any rock formation, they date back to just 100 million years after Earth formed.'],
  [41, 'A soft, ductile, gray-white metal with an unusually low density for its strength. Superconducting at very low temperatures.', 'Found primarily in the mineral pyrochlore. Brazil holds an extraordinary 92% of the world\'s niobium reserves.', 'High-strength steel alloys for pipelines and cars, superconducting magnets in MRI machines, and particle accelerators like the Large Hadron Collider.', 'The Large Hadron Collider at CERN uses niobium-titanium superconducting wire for its magnets — cooled near absolute zero, it carries enormous currents with zero electrical resistance.'],
  [42, 'A hard, silvery-white metal with the sixth-highest melting point of any element. An essential trace nutrient for nitrogen-fixing bacteria.', 'Found in molybdenite ore. China, the US, and Chile are the largest producers.', 'High-strength steel alloys for drill bits, engines, and military armor. Also an essential cofactor in bacterial enzymes that fix atmospheric nitrogen into soil.', 'Molybdenum was confused with graphite and lead for centuries because all three are soft, gray, and leave marks on paper. It was not recognized as a distinct element until 1781.'],
  [43, 'The lightest element with no stable isotopes — every form of technetium is radioactive. The first element to be artificially produced by humans.', "Virtually absent from Earth's crust naturally. Tiny traces exist from spontaneous fission of uranium, but it must otherwise be produced in nuclear reactors.", 'Medical imaging — technetium-99m is the most widely used radioactive tracer in nuclear medicine, used in millions of diagnostic scans every year.', 'Mendeleev left a blank space for this element (he called it "eka-manganese") in 1871. It took until 1937 to produce it artificially — more than 60 years after it was predicted to exist.'],
  [44, 'A rare, hard, silvery-white platinum group metal with a remarkably high melting point. One of the least reactive metals known.', 'Found with other platinum group metals in platinum ores. South Africa and Russia are the major sources.', 'Electrical contacts and resistors in hard disk drives, pen nibs, and as a catalyst in industrial chemistry.', 'Ruthenium tetroxide, formed when ruthenium oxidizes, is extraordinarily toxic and smells exactly like ozone. Chemists handling it must work in fully sealed environments.'],
  [45, 'One of the rarest and most expensive metals on Earth — a hard, silvery-white platinum group metal with exceptional reflectivity.', 'Found in platinum ores in tiny quantities. South Africa produces about 80% of the world\'s supply.', 'The catalytic converter in every gasoline car — rhodium converts nitrogen oxides (smog) back into harmless nitrogen gas.', 'Rhodium fluctuates wildly in price — at its 2021 peak, it was worth over $29,000 per troy ounce, more than 18 times the price of gold.'],
  [46, "A rare, lustrous silvery-white platinum group metal with the unusual ability to absorb up to 900 times its own volume in hydrogen gas.", 'Found with platinum and nickel ores. Russia and South Africa are the main producers.', 'Catalytic converters (majority of use), electronics, dental alloys, and hydrogen purification membranes.', "In 1989, Pons and Fleischmann famously claimed to achieve 'cold fusion' using a palladium electrode — one of the biggest science controversies of the 20th century that could never be replicated."],
  [47, 'A lustrous, soft, white metal with the highest electrical and thermal conductivity of any element. Prized since antiquity.', 'Found as native silver, in silver sulfide minerals, and as a byproduct of lead, zinc, and copper mining. Mexico, China, and Peru are major producers.', 'Electrical contacts and conductors, photography (historically), jewelry, silverware, and medical antimicrobial applications.', 'Before refrigeration, people stored milk in silver containers to keep it fresh — silver ions naturally kill bacteria. This is why silver-coated bandages and wound dressings are still used today.'],
  [48, 'A soft, bluish-white metal that is highly toxic and a known carcinogen, yet was widely used in rechargeable batteries and artist pigments.', 'A byproduct of zinc mining — almost all cadmium comes from processing zinc ores. Also found in phosphate fertilizers in concerning quantities.', 'Nickel-cadmium rechargeable batteries, yellow and orange pigments in artists\' paints, and electroplating.', "Japan suffered one of history's worst environmental crises — 'itai-itai disease' (it hurts, it hurts) — when cadmium from a zinc mine contaminated a river and entered the food supply through rice crops."],
  [49, "A soft, malleable, silvery-white post-transition metal that emits a high-pitched 'cry' when bent, caused by crystal structure breaking and reforming.", 'Almost entirely a byproduct of zinc processing. No primary indium mines exist anywhere in the world.', 'The transparent conducting layer in every touchscreen device (indium tin oxide), flat panel displays, and solar cells.', 'Every smartphone relies on indium for its touchscreen. With no primary ore deposits and all indium coming from zinc refining, it is one of the most quietly critical tech metals.'],
  [50, "A silvery-white, malleable metal that makes a distinctive 'tin cry' sound when bent — the sound of its crystal structure breaking and reforming.", 'Found primarily in cassiterite ore. China, Indonesia, and Myanmar are the main producers.', "Tin cans (thin steel coated with tin to prevent rust), solder, bronze (tin + copper), and pewter.", "'Tin pest' is real — below 13°C (56°F), tin slowly crumbles into gray powder. Napoleon's army's tin uniform buttons may have crumbled in the Russian winter, though historians debate whether this actually happened."],
  [51, 'A lustrous, silver-gray metalloid that is brittle and expands when it solidifies — unusual among elements.', "Found mainly in stibnite ore. China produces about 80% of the world's antimony.", 'Flame retardants (added to plastics and textiles), lead-acid car batteries (hardens lead), and historically as a cosmetic (kohl eyeliner in ancient Egypt).', 'The ancient Egyptians used antimony sulfide as black eye makeup, believing it had protective and mystical properties. Trace amounts can still be found in 3,000-year-old containers.'],
  [52, 'A brittle, silvery-white metalloid that smells faintly of garlic when handled. One of the rarest stable solid elements in Earth\'s crust.', "A byproduct of copper refining. Rarer than platinum in Earth's crust, though it was once dismissively named from 'tellus' (Earth) by a scientist who didn't think it was special.", "Cadmium telluride solar panels, alloys to improve machinability of steel, and rewritable DVDs.", "Tellurium is actually rarer in Earth's crust than gold, yet has a tiny fraction of gold's market value — because unlike gold, it has no thousands of years of human demand built around it."],
  [53, 'A shiny, dark gray nonmetal that sublimates (turns directly from solid to violet gas) at room temperature. Essential to the thyroid gland.', 'Found in seawater, certain minerals, and as a byproduct of natural gas processing. Some inland regions have iodine-deficient soils, which historically caused health problems.', 'Table salt iodization (prevents goiter and thyroid disease), wound antiseptic, and thyroid disease treatment.', "Before iodized salt became universal in the 1920s, iodine deficiency was the leading cause of preventable intellectual disability worldwide. Adding iodine to salt is one of the most cost-effective public health interventions in history."],
  [54, 'A dense, colorless noble gas that glows blue-white in electrical discharge. Despite being "noble," it can form chemical compounds under extreme conditions.', "Present in tiny trace amounts in Earth's atmosphere (1 part per 11.5 million). Produced by distilling liquid air.", 'High-intensity arc lamps (movie projectors, car headlights), ion propulsion in spacecraft, and as a medical anesthetic.', 'In 1989, IBM researchers used a scanning tunneling microscope to arrange 35 xenon atoms on a nickel surface to spell "IBM" — the first time individual atoms were deliberately positioned. It launched the era of nanotechnology.'],
  [55, 'A soft, golden-yellow alkali metal with the lowest melting point of any metal except mercury — it melts at just 28.5°C (83°F), around warm room temperature.', 'Found in pollucite mineral. Canada, Zimbabwe, and Namibia have major deposits. The Tanco mine in Manitoba was historically the primary world source.', 'Atomic clocks (cesium-133 defines the official second used worldwide), oil and gas drilling fluids, and night-vision devices.', 'The international definition of one second is exactly 9,192,631,770 oscillations of cesium-133 atoms. Every GPS satellite, internet server, and financial exchange runs on cesium time.'],
  [56, 'A soft, silvery-white alkaline earth metal that is dense and highly reactive. Barium compounds are toxic, but one application is swallowed in hospitals every day.', 'Found in barite (barium sulfate) and witherite (barium carbonate) minerals. Common worldwide.', 'Barium sulfate is swallowed as a "barium meal" for GI X-rays (it is opaque to X-rays but passes through safely), oil drilling fluids, and green fireworks.', 'The same element that makes barium toxic in one form (barium chloride) is completely safe in another (barium sulfate for medical X-rays) — the insolubility of the compound makes all the difference.'],
  [57, 'A soft, malleable, silvery-white rare earth metal that tarnishes quickly in air. The first of the lanthanide series.', 'Found in rare earth minerals like monazite and bastnäsite. China dominates global production of rare earths including lanthanum.', 'Hybrid car batteries (lanthanum nickel hydride is the cathode material), camera and telescope lenses, and carbon arc lamps for film studio lighting.', 'A Toyota Prius battery contains about 10–15 kg of lanthanum — more lanthanum than any other material in a typical hybrid car.'],
  [58, "The most abundant rare earth element, a ductile, iron-gray metal that ignites spontaneously when scratched. The 'rare' in rare earth is misleading — cerium is more abundant than copper.", "Found in rare earth minerals. More abundant in Earth's crust than tin or lead. China is the dominant producer.", "Catalytic converters (removes hydrocarbons from exhaust), self-cleaning ovens, and lighter flints (ferrocerium).", "The flint in every cigarette lighter isn't flint — it's ferrocerium, an alloy containing mostly cerium. When scratched, it throws sparks hot enough to ignite fuel."],
  [59, "A soft, silvery, malleable rare earth metal that tarnishes slowly in air. The name means 'green twin' in Greek.", 'Found alongside other rare earth elements in monazite and bastnäsite. China is the dominant producer.', 'High-strength alloys for aircraft engines (praseodymium-magnesium alloys), permanent magnets (used with neodymium), and yellow-orange glass for goggles worn by glassblowers and welders.', "Praseodymium and neodymium were once thought to be a single element called 'didymium.' It took until 1885 for Carl Welsbach to separate them into two distinct elements."],
  [60, "A silvery-white rare earth metal that forms the strongest permanent magnets known. Despite the name, it is actually quite abundant in Earth's crust.", 'Found in rare earth ore deposits. China controls the majority of global production and has used this position as geopolitical leverage.', 'The magnets in every electric motor, hard drive, wind turbine, electric vehicle, and speaker. Neodymium magnets power the modern world.', 'A neodymium magnet the size of a golf ball can lift over 300 pounds. These magnets are so strong that two large ones snapping together can shatter fingers.'],
  [61, 'A radioactive rare earth metal with no stable isotopes. Named after the mythological titan Prometheus, who stole fire from the gods.', 'Essentially absent from Earth\'s crust — it must be produced artificially in nuclear reactors. Tiny traces form naturally from uranium fission in rock.', 'Nuclear-powered pacemakers (historical), luminous paint (historical), and as a radioactive power source in some scientific instruments.', "Promethium is one of only two elements with atomic number below 83 that has no stable isotopes — it literally doesn't persist in nature. Every atom decays away in decades."],
  [62, 'A moderately hard, silvery rare earth metal that forms powerful permanent magnets with cobalt. Named after a Russian mine official.', 'Found in rare earth minerals, fairly widely distributed. The first element named after a living person (indirectly — named after a mine named after a mine manager).', 'Samarium-cobalt magnets for high-temperature applications (they outperform neodymium at high heat), and samarium-153 as a targeted treatment for bone tumors.', 'Samarium is the first element named (indirectly) after a person — specifically, Vasili Samarsky-Bykhovets, a Russian mining official. All elements named directly after people came later.'],
  [63, 'A rare earth metal so reactive it burns in air at room temperature. Most famous for its brilliant luminescence — it makes phosphors glow vividly red and blue.', 'Found in rare earth minerals and monazite sand.', 'The red and blue phosphors in LED screens and fluorescent lights. Euro banknotes contain europium-doped ink that glows red under UV light as an anti-counterfeiting measure.', 'The red color on all Euro banknotes is a europium compound that glows distinctively under ultraviolet light — it is one of the hardest security features to replicate.'],
  [64, "A silvery-white rare earth metal with the highest neutron absorption capacity of any known element. Strongly magnetic near room temperature.", 'Found in gadolinite mineral and other rare earth ores.', 'MRI contrast agents (injected to make tissues more visible in scans), neutron shielding in nuclear reactors, and magnetocaloric refrigeration research.', 'Gadolinium is injected into millions of MRI patients every year as a contrast agent. Recent research has found it accumulates in brain tissue with repeated use — long-term effects are still under study.'],
  [65, "A silvery-white rare earth metal that changes size when placed in a magnetic field — a property called magnetostriction. Soft enough to cut with a knife.", 'Found with other rare earth elements in gadolinite and xenotime. One of four elements named after Ytterby village in Sweden.', 'Green phosphors in LED and fluorescent lighting, sonar devices (magnetostriction makes it vibrate to produce sound), and data storage research.', 'Terbium-based green phosphors are used in the fluorescent tubes that light offices worldwide. Without terbium, fluorescent lighting would not produce a pleasing white light.'],
  [66, "A rare earth metal that holds the record for highest magnetic strength of any natural element. Its name means 'hard to get' in Greek.", 'Found in rare earth ores. Most production comes from China.', 'Neodymium magnets need dysprosium to work at high temperatures — electric vehicle motors would demagnetize without it. Also used in nuclear reactor control rods.', "Electric vehicles and wind turbines couldn't function in hot conditions without dysprosium — even a small percentage keeps neodymium magnets working in a hot engine."],
  [67, "A soft, silvery rare earth metal with the highest magnetic moment of any naturally occurring element, meaning it has an unusually strong response to magnetic fields.", 'Found in rare earth minerals alongside erbium and ytterbium. Never found in large concentrations.', 'The most powerful continuous wave lasers (holmium lasers are used in eye surgery and kidney stone treatment), and nuclear reactor control rods.', 'Holmium lasers are used to vaporize kidney stones from the inside — a fiber optic probe carries the laser into the ureter, breaking stones into dust that passes naturally.'],
  [68, 'A soft, silvery rare earth metal whose pink ions are responsible for amplifying signals in fiber optic cables — one of the most important elements in modern telecommunications.', 'Found with other rare earth elements in xenotime and euxenite minerals. One of four elements named after Ytterby, Sweden.', 'Erbium-doped fiber amplifiers allow fiber optic signals to travel thousands of miles without degradation — they are the reason the modern internet is possible.', 'Every time you use the internet over fiber optics, your data was amplified by erbium atoms excited by lasers. Without erbium, fiber optic networks would only work over short distances.'],
  [69, 'The second rarest naturally occurring lanthanide. A silvery-gray rare earth metal among the least studied of all elements.', 'Found in trace amounts in rare earth minerals. Never concentrated enough to mine directly — always a byproduct.', 'Portable X-ray devices using thulium-170 (used in field medicine and security screening) and laser applications.', "Thulium is named after Thule, the ancient mythological name for the far north. It is so rare and obscure that most chemists go their entire careers without working with it."],
  [70, 'A soft, silvery rare earth metal with unusual optical properties. One of four elements named after Ytterby, Sweden.', 'Found in rare earth mineral deposits. Usually extracted as a byproduct of other rare earth mining.', 'The most accurate atomic clocks in existence (ytterbium lattice clocks), fiber optic amplifiers, and as a doping agent in stainless steel.', 'Ytterbium lattice clocks are so precise they would gain or lose less than 1 second in the entire age of the universe (13.8 billion years). They can detect the passage of time differently at heights just centimeters apart.'],
  [71, 'The heaviest and hardest of the lanthanide series, and one of the rarest naturally occurring lanthanides. The last of the rare earth elements.', 'Found in rare earth minerals. Named after Lutetia, the ancient Latin name for Paris.', 'PET scan detectors (lutetium oxyorthosilicate crystals), cancer therapy (lutetium-177 is a targeted radiotherapy agent), and catalysts in petroleum refining.', 'Lutetium-177 is emerging as a powerful cancer treatment — attached to molecules that seek specific tumors, it irradiates them from the inside with minimal damage to surrounding tissue.'],
  [72, "A shiny, silvery-gray metal that is remarkably similar to zirconium — they are so alike it took decades after zirconium's discovery to notice hafnium was hiding inside it.", 'Always found alongside zirconium — never separately. Zirconium minerals always contain a small percentage of hafnium.', "Nuclear reactor control rods (it absorbs neutrons extremely well), next-generation computer chip transistors (hafnium oxide replaced silicon oxide after 2007), and aerospace alloys.", "Intel's shift from silicon oxide to hafnium oxide in chip transistors in 2007 was described as the biggest change in transistor materials since the 1960s — hafnium is literally inside every modern computer processor."],
  [73, "A hard, blue-gray metal with one of the highest melting points of any element. Completely inert to body fluids — the body doesn't react to it at all.", 'Found in tantalite-columbite ore, primarily in Central Africa. Also called "coltan" in its raw ore form. DRC holds major reserves.', 'Capacitors in electronic devices (most smartphones contain tantalum capacitors), surgical implants, and superalloys for jet engines.', "The tantalum in your phone likely came from the DRC, where 'coltan' mining has been linked to funding armed conflict — making it one of the 'conflict minerals' covered by US disclosure laws."],
  [74, 'The element with the highest melting point of any metal (3,422°C / 6,192°F) and the highest tensile strength at high temperatures.', 'Found primarily in wolframite and scheelite minerals. China produces about 80% of the world\'s tungsten.', "Incandescent light bulb filaments (tungsten can glow white-hot without melting), cutting tools, armor-piercing ammunition, and ballast weights.", "Tungsten's symbol W comes from 'wolfram' — the German name for the element. It was named wolfram because the ore 'devoured' tin during smelting, described as 'like a wolf devours sheep.'"],
  [75, "One of the rarest elements in Earth's crust and one of the last stable elements discovered (1925). Has the second-highest melting point of any element after tungsten.", 'Found in tiny amounts in molybdenite — rhenium is a trace byproduct of molybdenum mining. Chile is the largest producer.', 'Superalloy turbine blades in jet engines (a few percent rhenium dramatically improves performance at extreme temperatures) and platinum-rhenium catalysts in petroleum refining.', 'Almost all commercial aircraft turbine blades contain rhenium — it is the element that lets jet engines run at temperatures above the melting point of most materials without failing.'],
  [76, "The densest naturally occurring element — a chunk of osmium the size of a baseball weighs about 14 pounds. Also among the rarest elements on Earth.", 'Found in platinum ores. South Africa and Russia are the primary sources.', 'The hardest natural alloy (osmium-iridium) for pen nibs and pivot bearings in precision instruments, and as a staining agent in electron microscopy.', "Osmium tetroxide, formed when osmium oxidizes in air, is extraordinarily toxic — it stains biological tissue on contact and can cause blindness. The element is named for its smell ('osme' = smell in Greek)."],
  [77, "The most corrosion-resistant element known — nothing dissolves it except molten salts at very high temperatures. The second densest element after osmium.", 'Extremely rare in Earth\'s crust but more common in meteorites. South Africa and Russia are the major sources.', 'Spark plug electrodes (iridium-tipped plugs last 100,000 miles), crucibles for growing crystals, and as a hardening alloy for platinum jewelry.', 'A thin layer of iridium-rich clay marks the K-Pg boundary worldwide — the geological signature of the asteroid that killed the dinosaurs 66 million years ago. Meteorites carry far more iridium than Earth\'s crust, and its global presence proved the impact theory.'],
  [78, 'A dense, malleable, silvery-white precious metal with exceptional catalytic properties. More rare and more durable than gold.', "Found in platinum ore deposits in South Africa (which produces ~70% of the world's supply) and Russia.", "Catalytic converters (the majority of platinum use), jewelry, cancer treatment (cisplatin is a platinum compound), and laboratory equipment.", 'The kilogram was defined until 2019 by a physical platinum-iridium cylinder kept under glass bells in Paris. Every scale in the world was calibrated against that single 130-year-old object.'],
  [79, "A dense, soft, shiny, and malleable precious metal with a distinctive yellow color. Does not tarnish, corrode, or react with most chemicals — truly noble.", "Found in alluvial deposits, hydrothermal veins, and with other metals in ore. South Africa, China, Russia, and Australia are major producers.", "Jewelry, monetary reserves, electronics (gold-plated connectors resist corrosion), and dentistry.", "All the gold ever mined in human history — roughly 190,000 metric tons — would form a cube only about 21 meters (69 feet) on each side. It would fit under the Eiffel Tower."],
  [80, "The only metal that is liquid at room temperature. One of only two elements liquid at standard conditions (with bromine). Highly toxic.", "Found as cinnabar (mercury sulfide) ore. Spain and Italy historically; China and Kyrgyzstan are now major sources.", "Thermometers and barometers (increasingly replaced), fluorescent lights, and gold mining (mercury-gold amalgamation, now largely illegal).", "Mercury inspired the phrase 'mad as a hatter' — hatters used mercury nitrate to cure felt and developed tremors and personality changes from chronic exposure. Its symbol Hg comes from 'hydrargyrum,' Greek for 'water silver.'"],
  [81, "A soft, gray post-transition metal. Highly toxic — odorless, tasteless, and soluble in water, making it historically a notorious poison of choice.", 'Found as a trace element in potassium minerals and as a byproduct of lead and zinc refining.', 'Medical imaging (thallium-201 is used in cardiac stress tests), infrared detectors, and historically as rat poison and insecticide (now banned in most countries).', 'Thallium poisoning was a preferred method of Cold War assassination — the KGB reportedly used it to kill Soviet defectors. Agatha Christie used her pharmacy knowledge to write it into detective novels.'],
  [82, "A dense, soft, bluish-gray post-transition metal. One of the earliest metals used by humans. Its toxicity was recognized in antiquity but widely ignored for millennia.", 'Found in galena (lead sulfide) ore. Widely distributed around the world.', "Car batteries (the biggest use today), radiation shielding (in medical and nuclear facilities), and historically in paint and gasoline (both now banned).", "Some historians argue that lead poisoning contributed to the fall of the Roman Empire — Romans used lead pipes for water, lead-lined vessels for wine, and lead acetate ('sugar of lead') as a food sweetener."],
  [83, 'A heavy, brittle post-transition metal with a beautiful iridescent pink-silver color. Grows in spectacular staircase-shaped crystals with rainbow oxide films.', 'Found as bismuthinite ore and as a byproduct of lead, tin, and copper refining.', 'Pepto-Bismol (bismuth subsalicylate), lead-free solders, and cosmetics (bismuth oxychloride gives cosmetics their shimmer).', 'Bismuth was long considered the heaviest stable element. In 2003, physicists discovered it is very slightly radioactive — but with a half-life of 20 quintillion years, over a billion times the age of the universe.'],
  [84, 'A highly radioactive, extremely rare metalloid with no stable isotopes. One of the most toxic substances known — lethal in microgram quantities.', "Vanishingly rare in nature — formed from radioactive decay of uranium in rocks. Must be produced in nuclear reactors for any practical use.", 'Anti-static brushes for film and electronics, neutron sources in research, and most infamously as an assassination weapon.', 'Alexander Litvinenko, a former Russian spy, was poisoned with polonium-210 in London in 2006 — an estimated 10 micrograms is thought to have been used. The assassination left a radioactive trail traced across dozens of London locations.'],
  [85, "The rarest naturally occurring element on Earth — at any given moment, less than 30 grams of astatine exists in the entire planet's crust.", "Formed by radioactive decay of heavier elements in deep rock in trace amounts. Completely absent from Earth's surface.", 'Research into targeted cancer therapy — astatine-211 can attach to molecules that seek out tumors and irradiate them from within, with very short range that limits damage to surrounding tissue.', "The entire Earth contains less than an ounce of astatine at any moment. If you collected all naturally occurring astatine on the planet, you couldn't see it with the naked eye."],
  [86, "A colorless, radioactive noble gas produced by the decay of uranium and radium in rocks and soil. The second leading cause of lung cancer in the United States.", "Seeps up from uranium-bearing rocks and soil into buildings. Accumulates in basements and low-lying areas. Particularly concentrated in granite-rich regions.", 'Historically used in cancer radiotherapy. Now studied primarily as a health hazard to be detected and mitigated in buildings.', "Radon is responsible for about 21,000 lung cancer deaths per year in the US — more than drunk driving. It's invisible, odorless, and most homeowners are completely unaware it may be seeping into their basements."],
  [87, "The second rarest naturally occurring element and one of the most unstable. The last element to be discovered in nature (1939).", "A decay product of actinium in uranium ore. At any moment, less than 30 grams exists naturally in Earth's entire crust.", 'No practical uses — too rare and short-lived. Used only in atomic physics research to study the properties of large alkali metal atoms.', 'No one has ever seen a visible sample of francium. The most ever produced at once is a cluster of about 300,000 atoms, visible only as a faint glow in laser light — roughly 10⁻¹⁷ grams.'],
  [88, 'A brilliant white, highly radioactive alkaline earth metal that glows faintly blue in the dark from Cherenkov radiation. Discovered by Marie Curie in 1898.', "Found in trace amounts in uranium ore. Marie Curie processed tons of pitchblende to isolate a few decigrams of radium.", 'Historically used in luminous watch and instrument dials, cancer treatment, and as a neutron source. Now largely replaced by safer alternatives.', "The 'Radium Girls' — factory workers who painted watch dials with radium-based paint in the 1920s and were told to point their brushes with their lips — developed horrific bone cancers. Their lawsuits established workers' legal right to sue employers for occupational health damages."],
  [89, 'A soft, silvery-white radioactive metal so radioactive it glows blue in the dark. The first actinide and one of the rarest elements in Earth\'s crust.', 'Found in tiny amounts in uranium ore as a decay product — about 0.2 milligrams per ton of ore.', 'Actinium-225 is a highly promising cancer therapy agent — it decays in a chain that delivers multiple doses of targeted radiation directly inside tumors.', 'Actinium is so radioactive that a small sample heats itself through radioactive decay, remaining noticeably warm to the touch with no external heat source.'],
  [90, 'A weakly radioactive, silvery, lustrous metal more abundant in Earth\'s crust than tin or lead. A potential fuel source for cleaner nuclear power.', 'Found in monazite sand alongside rare earth elements. India, Brazil, and Australia have large deposits.', 'Thorium reactors (still largely experimental) as a nuclear fuel, formerly in gas lantern mantles (which made them intensely bright), and in high-refractive-index optical glass.', 'Thorium-based nuclear reactors could use nuclear waste as fuel and produce far less long-lived waste than conventional uranium reactors. India, China, and Norway are actively developing this technology.'],
  [91, 'A dense, shiny, silvery-gray radioactive metal. Toxic and highly radioactive. One of the rarest and least studied of the naturally occurring elements.', "Found in trace amounts in uranium ores as a decay product. Less than a kilogram exists in Earth's entire accessible crust.", 'No commercial applications — too rare, expensive, and radioactive. Used in scientific studies of nuclear properties.', 'To isolate just 125 grams of protactinium, the UK Atomic Energy Authority processed 60 metric tons of nuclear waste residue over 5 years in the 1960s. It remains one of the most expensive element isolation efforts ever attempted.'],
  [92, 'A dense, weakly radioactive, silvery-gray actinide metal. The heaviest naturally occurring element and the fuel of the nuclear age.', 'Found in uraninite (pitchblende) ore. Kazakhstan, Canada, and Australia are the largest producers.', 'Nuclear power (provides about 10% of global electricity), nuclear weapons, depleted uranium armor and ammunition, and historically as a yellow glass colorant.', 'The energy density of uranium is almost incomprehensible — one kilogram of uranium fuel contains as much energy as about 3 million kilograms of coal. A single fuel pellet the size of a finger can power an average home for 5 years.'],
  [93, "The first transuranic element — the first element heavier than uranium ever produced. A silvery, radioactive actinide that doesn't occur naturally in significant amounts.", "Trace amounts form from neutron bombardment of uranium in nature. Primarily produced in nuclear reactors as a byproduct of uranium fuel use.", "Neutron detection instruments, and as a precursor to plutonium-238 used in spacecraft power systems.", "Neptunium was the first element produced artificially in significant quantities (1940). It was named after Neptune because it follows uranium — just as Neptune follows Uranus in the solar system."],
  [94, 'A radioactive actinide metal with a warm, almost biological feel due to its own radioactive decay generating heat. Exists in six different crystalline forms.', "Essentially absent in nature. Primarily made in nuclear reactors through neutron bombardment of uranium.", 'Nuclear weapons, nuclear power, and spacecraft power systems (Voyager, Cassini, and New Horizons are powered by plutonium-238 RTGs).', "The plutonium in your body (from atmospheric nuclear tests) amounts to about 0.1 nanocuries — completely undetectable but measurably present. Every human born after 1945 contains trace amounts of man-made plutonium."],
  [95, 'A radioactive actinide metal named after the Americas. Despite its nuclear origins, it sits in homes across the world — in smoke detectors.', 'Does not exist in nature. Produced in nuclear reactors by neutron bombardment of plutonium.', 'The ionization chamber in most household smoke detectors contains a tiny speck of americium-241, which ionizes air to detect smoke particles.', 'About 43,000 smoke detectors are sold every day in the US. Each contains americium-241 — a synthetic radioactive element — sitting quietly on walls in over 100 million American homes.'],
  [96, 'A radioactive actinide metal so intensely radioactive that a small sample glows purple-red in the dark and generates significant heat. Named after Marie and Pierre Curie.', 'Does not occur naturally. Produced in nuclear reactors by bombarding plutonium or americium with neutrons.', 'Power source for spacecraft instruments — curium-244 has powered scientific equipment on NASA missions. Also used in the alpha particle X-ray spectrometer on Mars rovers.', 'The Mars rovers Spirit, Opportunity, Curiosity, and Perseverance all carry curium-244 as the radioactive source in their rock and soil analysis instruments.'],
  [97, 'A synthetic, radioactive actinide metal produced only in microscopic quantities. Named after Berkeley, California, where it was first synthesized.', 'Does not occur naturally. Produced only at Oak Ridge National Laboratory and a few facilities worldwide — annual production is measured in micrograms.', 'Production of even heavier elements — tennessine (element 117) was made using berkelium as a target. No commercial uses exist.', 'To synthesize element 117 (tennessine) in 2010, scientists first had to make 22 milligrams of berkelium-249 at Oak Ridge over 250 days — a larger quantity of berkelium than had ever been produced before.'],
  [98, 'A highly radioactive synthetic actinide that can sustain a nuclear chain reaction with remarkably little material — a property that makes it both valuable and dangerous.', 'Does not occur naturally. Produced in nuclear reactors or particle accelerators. Annual global production is only a few milligrams.', 'Starting up nuclear reactors (as a portable neutron source), detecting gold and silver ore underground, and treating certain cancers (californium-252 brachytherapy).', 'Californium is one of the most expensive substances on Earth — approximately $27 million per gram. Only a handful of grams have ever been produced in all of human history.'],
  [99, 'A radioactive synthetic actinide named after Albert Einstein. First discovered in the fallout from the first hydrogen bomb test in 1952.', 'Found in the fallout debris of nuclear explosions. Produced in small amounts in nuclear reactors.', 'No practical applications — too rare and short-lived. Used to produce heavier elements in research.', 'Einsteinium was discovered in the top-secret aftermath of the 1952 Ivy Mike thermonuclear test. The discovery was classified for years while scientists quietly published papers about it without revealing the nuclear test origin.'],
  [100, 'A radioactive synthetic actinide named after Enrico Fermi, creator of the first nuclear reactor. The heaviest element that can be produced by neutron bombardment alone.', 'Also first found in hydrogen bomb fallout alongside einsteinium. Produced in nuclear reactors in very small quantities.', 'No practical applications — production amounts are far too small. Research purposes only.', 'Fermium marks a practical boundary in element production — elements heavier than fermium cannot be made by adding neutrons in a reactor (nuclei become too unstable too fast), so heavier elements require particle accelerators.'],
  [101, 'A radioactive synthetic actinide named after Dmitri Mendeleev, creator of the periodic table. The first element produced one atom at a time.', 'Does not occur in nature. Produced by bombarding einsteinium with alpha particles in a cyclotron.', 'No practical applications. Produced in quantities of a few atoms to a few thousand atoms at a time, for nuclear physics research only.', "When mendelevium was first synthesized in 1955, the team produced fewer than 17 atoms total. They identified the new element from that single experiment — detecting elements one atom at a time requires extraordinary technique."],
  [102, 'A radioactive synthetic actinide named after Alfred Nobel. Extremely short-lived — its longest-lived isotope lasts only 58 minutes.', 'Does not occur naturally. Produced by heavy ion bombardment of curium targets in particle accelerators.', 'No practical applications. Produced in quantities of tens of atoms at a time for nuclear physics research.', "Nobelium's discovery was disputed for years between American, Soviet, and Swedish teams — each claimed first synthesis, and the naming became a Cold War political argument settled only through international scientific arbitration."],
  [103, 'The final actinide element and the last element of the f-block. A radioactive synthetic element named after Ernest Lawrence, inventor of the cyclotron.', 'Does not occur naturally. Synthesized in particle accelerators.', 'No practical applications. Research into the chemical boundary between actinides and transition metals.', "Lawrencium sits at an unusual chemical borderline — determining its electron configuration took decades and revealed surprising behavior at the edge of the periodic table."],
  [104, "The first transactinide element and the first superheavy element. Named after Ernest Rutherford. Exists for only seconds before decaying.", "Does not occur in nature. Produced in heavy-ion accelerators by bombarding californium with carbon ions.", "Pure research into the chemistry of superheavy elements.", "Rutherfordium was at the center of a Cold War naming dispute — the US called it 'rutherfordium' while the Soviets called it 'kurchatovium.' The International Union of Pure and Applied Chemistry settled the dispute in 1997."],
  [105, "A radioactive synthetic transactinide element named after Dubna, Russia, home of the Joint Institute for Nuclear Research. Lasts for only seconds.", "Does not occur naturally. Produced in particle accelerators.", "Pure research only — too unstable and rare for any application.", "Another Cold War naming dispute — the US called it 'hahnium,' the Soviets called it 'nielsbohrium.' The neutral name 'dubnium' was chosen as a diplomatic compromise."],
  [106, "A radioactive synthetic element named after Glenn T. Seaborg, discoverer of many transuranium elements. One of the few elements named after a living person at the time of naming.", "Does not occur naturally. Produced in particle accelerators.", "Research only.", "Glenn Seaborg is the only person to have an element named after them while still alive (1997). He reportedly heard about it on a radio call-in show before being officially notified by the naming committee."],
  [107, "A radioactive synthetic transactinide element named after Niels Bohr, the Danish physicist who pioneered quantum mechanics.", "Does not occur naturally. Produced in particle accelerators by bombarding bismuth with chromium ions.", "Research only. Only a few hundred atoms have ever been produced.", "Each atom of bohrium lasts about 17 seconds before decaying. The element has been produced in total quantities countable in hundreds of individual atoms."],
  [108, "A radioactive synthetic element named after the German state of Hesse, where the GSI Helmholtz Centre — a major heavy-element research facility — is located.", "Does not occur naturally. Produced in particle accelerators.", "Research only. Chemically, hassium is expected to behave like osmium (same periodic table group).", "In 2002, scientists made hassium oxide — an actual chemical compound of a superheavy element — and analyzed it while the atoms were literally decaying during measurement. A remarkable feat of speed chemistry."],
  [109, "A radioactive synthetic element named after Lise Meitner, the physicist who co-discovered nuclear fission. Named in 1997.", "Does not occur naturally. Produced in particle accelerators.", "Research only.", "Lise Meitner was passed over for the Nobel Prize despite co-discovering nuclear fission — her colleague Otto Hahn received it alone. Meitnerium, named in her honor, is considered a long-overdue recognition. She was nominated for the Nobel 48 times."],
  [110, "A radioactive synthetic transactinide element named after Darmstadt, Germany, where it was first synthesized at GSI.", "Does not occur naturally. Produced in particle accelerators.", "Research only. Its chemistry is expected to resemble platinum.", "In 2003, scientists synthesized 9 atoms of darmstadtium in a single experiment — considered a high yield for superheavy element research, where success is measured in single atoms."],
  [111, "A radioactive synthetic element named after Wilhelm Röntgen, discoverer of X-rays. Predicted to have unusual chemical properties unlike its neighbors.", "Does not occur naturally. Produced in particle accelerators.", "Research only.", "Roentgenium is predicted by relativistic quantum chemistry to be a gas at room temperature — despite being in the same group as copper, silver, and gold. Extreme relativistic effects on its electrons change everything."],
  [112, "A radioactive synthetic element named after Nicolaus Copernicus. The heaviest element of the transition metals, predicted to be a gas at room temperature.", "Does not occur naturally. Produced in particle accelerators.", "Research only.", "Copernicium is theoretically predicted to be a gas at room temperature despite being a metal — relativistic effects make its outer electrons so stable they don't bond like normal metals. It may be the first metallic element that is gaseous under normal conditions."],
  [113, "A radioactive synthetic element named after Japan (Nihon in Japanese) — the first element discovered in Asia.", "Does not occur naturally. First synthesized at RIKEN institute in Japan in 2004 after a decade of trying.", "Research only.", "The RIKEN team spent 9 years running their accelerator nearly continuously before producing enough nihonium atoms to confirm discovery. The naming by Japan was celebrated as a source of national pride."],
  [114, "A radioactive synthetic element named after the Flerov Laboratory of Nuclear Reactions in Russia. Predicted to potentially behave like a noble gas due to relativistic effects.", "Does not occur naturally. Produced by bombarding plutonium with calcium ions.", "Research only.", "Flerovium sits near a theoretical 'island of stability' — a region where superheavy elements might have unusually long half-lives. Some isotopes last nearly 3 seconds, remarkably long for a superheavy element."],
  [115, "A radioactive synthetic element named after Moscow Oblast, Russia. Part of the 'island of stability' neighborhood of superheavy elements.", "Does not occur naturally. Produced by bombarding americium with calcium ions at JINR in Dubna.", "Research only.", "Moscovium was announced alongside nihonium, tennessine, and oganesson in 2016 as part of the largest single batch of new elements formally named in one announcement in history."],
  [116, "A radioactive synthetic element named after Lawrence Livermore National Laboratory in California, which collaborated on its discovery with Russia's JINR.", "Does not occur naturally. Produced by bombarding curium with calcium ions.", "Research only.", "Livermorium decays to flerovium, then copernicium — tracking these decay chains in real time as atoms vanish is one of the primary tools for studying superheavy element properties."],
  [117, "A radioactive synthetic element named after Tennessee (Oak Ridge National Laboratory, Vanderbilt, and University of Tennessee all contributed). The second-heaviest known element.", "Does not occur naturally. Synthesized by bombarding berkelium-249 (produced at Oak Ridge) with calcium-48 ions at JINR in Dubna.", "Research only. Expected to have unusual chemical properties as a heavy halogen.", "Making tennessine required first producing 22 mg of pure berkelium-249 at Oak Ridge over 250 days, then shipping it to Russia within weeks before it decayed. A transatlantic scientific relay race against radioactive time."],
  [118, "The heaviest element ever synthesized and the last on the current periodic table. Named after physicist Yuri Oganessian — one of only two people to have an element named after them while living.", "Does not occur naturally. Only 5 confirmed atoms have ever been detected in human history. Each atom lasts less than a millisecond.", "Research only. Marks the end of the seventh period of the periodic table.", "Only 5 atoms of oganesson have ever been observed. Despite occupying the noble gas position, relativistic effects mean it may actually be a solid at room temperature — possibly the most 'un-noble' of all the noble gases."],
]

async function main() {
  console.log(`Populating facts for ${facts.length} elements...`)

  for (const [id, elementDescription, whereFound, usedFor, funFact] of facts) {
    await prisma.element.update({
      where: { id },
      data: { elementDescription, whereFound, usedFor, funFact },
    })
  }

  console.log('Done.')
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect())
